mapper.insert:
/* SQL ID : ExamStarePaperHstyDAO.insertExamStarePaperHsty 설 명 : 응시 시험지 이력 등록 */ INSERT INTO TB_LMS_EXAM_STARE_PAPER_HSTY ( EXAM_STARE_PAPER_HSTY_SN , STARE_HSTY_SN , EXAM_ID , EXAM_QSTN_NO , STD_ID , QSTN_SEQNO , CNDDT_ID , STARE_ANSR , ACQS_SCR , QSTN_SEQ , FDBK_CTS , FDBK_DTTM , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) SELECT ROW_NUMBER() OVER(ORDER BY EXAM_QSTN_NO) + (SELECT NVL(MAX(EXAM_STARE_PAPER_HSTY_SN), 0) + 1 FROM TB_LMS_EXAM_STARE_PAPER_HSTY P) , #{stareHstySn} , EXAM_ID , EXAM_QSTN_NO , STD_ID , QSTN_SEQNO , CNDDT_ID , STARE_ANSR , ACQS_SCR , QSTN_SEQ , FDBK_CTS , FDBK_DTTM , #{rgtrId} , FN_DTTM() , #{mdfrId} , FN_DTTM() FROM TB_LMS_EXAM_STARE_PAPER WHERE EXAM_ID = #{examCd} AND STD_ID = #{stdNo}
AND EXAM_QSTN_NO IN
#{item}

